&lt;dd&gt;&lt;span class=&#34;red&#34;&gt;监督&lt;/span&gt;项目活动&lt;span class=&#34;red&#34;&gt;状态&lt;/span&gt;，&lt;span class=&#34;red&#34;&gt;更新&lt;/span&gt;项目&lt;span class=&#34;red&#34;&gt;进展&lt;/span&gt;，&lt;span class=&#34;red&#34;&gt;管理进度基准变更&lt;/span&gt;&lt;/dd&gt;
&lt;/dl&gt;
&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;
&lt;dl&gt;
