&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;估算活动持续时间&lt;/td&gt;
&lt;td&gt;活动资源需求、资源日历、项目范围说明书&lt;/td&gt;
&lt;td&gt;类比估算、参数估算、三点估算&lt;/td&gt;
&lt;td&gt;活动持续时间估算&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td rowspan=&#34;2&#34;&gt;制定进度计划&lt;/td&gt;
&lt;td&gt;项目进度网络图、活动资源需求、资源日历&lt;/td&gt;
&lt;td&gt;关键路径法、关键链法&lt;/td&gt;
&lt;td&gt;进度基准&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;活动持续时间估算、项目范围说明书&lt;/td&gt;
&lt;td&gt;资源优化技术、进度压缩&lt;/td&gt;
&lt;td&gt;项目进度计划&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td rowspan=&#34;2&#34;&gt;控制进度&lt;/td&gt;
&lt;td&gt;工作绩效数据&lt;/td&gt;
&lt;td rowspan=&#34;2&#34;&gt;偏差分析&lt;/td&gt;
&lt;td&gt;工作绩效信息&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;项目进度计划&lt;/td&gt;
&lt;td&gt;变更请求&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;

 &lt;p&gt;&lt;img data-src=&#34;https://i.loli.net/2021/07/28/Yi9SMEkjo4bFRLq.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;h1 id=&#34;项目范围管理-scope-management&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#项目范围管理-scope-management&#34;&gt;#&lt;/a&gt; 项目范围管理  &lt;code&gt;Scope Management&lt;/code&gt;&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;做且只做&lt;/span&gt;所需的全部工作。&lt;/li&gt;
&lt;/ul&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;启动过程组&lt;/th&gt;
&lt;th&gt;规划过程组&lt;/th&gt;
&lt;th&gt;执行过程组&lt;/th&gt;
&lt;th&gt;监控过程组&lt;/th&gt;
&lt;th&gt;收尾过程组&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;
&lt;dl&gt;
&lt;dt&gt;规划范围管理&lt;/dt&gt;
&lt;dd&gt;创建&lt;span class=&#34;red&#34;&gt;范围管理计划&lt;/span&gt;&lt;/dd&gt;
&lt;/dl&gt;
&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;
&lt;dl&gt;
&lt;dt&gt;确认范围&lt;/dt&gt;
&lt;dd&gt;&lt;span class=&#34;red&#34;&gt;正式验收&lt;/span&gt;已完成的项目可交付成果&lt;/dd&gt;
&lt;/dl&gt;
&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;
&lt;dl&gt;
&lt;dt&gt;收集需求&lt;/dt&gt;
&lt;dd&gt;&lt;span class=&#34;red&#34;&gt;确定、记录并管理&lt;/span&gt;干系人的需求&lt;/dd&gt;
&lt;/dl&gt;
&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;
&lt;dl&gt;
&lt;dt&gt;控制范围&lt;/dt&gt;
&lt;dd&gt;&lt;span class=&#34;red&#34;&gt;监督&lt;/span&gt;项目和产品的范围&lt;span class=&#34;red&#34;&gt;状态&lt;/span&gt;，&lt;span class=&#34;red&#34;&gt;管理&lt;/span&gt;范围基准&lt;span class=&#34;red&#34;&gt;变更&lt;/span&gt;&lt;/dd&gt;
&lt;/dl&gt;
&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;
&lt;dl&gt;
&lt;dt&gt;定义范围&lt;/dt&gt;
&lt;dd&gt;制定项目和产品&lt;span class=&#34;red&#34;&gt;详细&lt;/span&gt;描述&lt;/dd&gt;
&lt;/dl&gt;
&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;
&lt;dl&gt;
&lt;dt&gt;创建 WBS&lt;/dt&gt;
&lt;dd&gt;将项目可交付成果和项目工作&lt;span class=&#34;red&#34;&gt;分解&lt;/span&gt;，为较小的、更易于管理的组件&lt;/dd&gt;
&lt;/dl&gt;
&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;td&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;产品范围和项目范围&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#产品范围和项目范围&#34;&gt;#&lt;/a&gt; 产品范围和项目范围&lt;/h2&gt;
&lt;dl&gt;
&lt;dt&gt;产品范围&lt;/dt&gt;
&lt;dd&gt;某项产品、服务或成果所具有的&lt;span class=&#34;red&#34;&gt;特性和功能&lt;/span&gt;。&lt;/dd&gt;
&lt;dt&gt;项目范围&lt;/dt&gt;
&lt;dd&gt;为交付具有规定特性与功能的产品、服务或成果而必须完成的&lt;span class=&#34;red&#34;&gt;工作&lt;/span&gt;。&lt;/dd&gt;
&lt;/dl&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;&lt;/th&gt;
&lt;th&gt;产品范围&lt;/th&gt;
&lt;th&gt;项目范围&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;主导关系&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;&lt;span class=&#34;red&#34;&gt;决定&lt;/span&gt;项目范围&lt;/td&gt;
&lt;td&gt;&lt;span class=&#34;red&#34;&gt;服务于&lt;/span&gt;产品范围&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;影响关系&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;自身变化&lt;span class=&#34;red&#34;&gt;不一定&lt;/span&gt;会引起项目范围的变化&lt;/td&gt;
&lt;td&gt;自身变化&lt;span class=&#34;red&#34;&gt;不一定&lt;/span&gt;会引起产品范围的变化&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;包含关系&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;不包含项目范围&lt;/td&gt;
&lt;td&gt;广义上有时也包括产品范围&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;完成情况的考核依据&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;&lt;span class=&#34;red&#34;&gt;产品需求文件&lt;/span&gt;（如软件需求规格说明书）&lt;/td&gt;
&lt;td&gt;&lt;span class=&#34;red&#34;&gt;项目管理计划&lt;/span&gt;（范围基准）&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;范围蔓延&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#范围蔓延&#34;&gt;#&lt;/a&gt; 范围蔓延&lt;/h2&gt;
&lt;ul&gt;
&lt;li&gt;未对时间、成本和资源做相应调整，&lt;span class=&#34;red&#34;&gt;未经控制&lt;/span&gt;的产品或项目范围的扩大。
&lt;ul&gt;
&lt;li&gt;来自团队&lt;span class=&#34;red&#34;&gt;内部原因&lt;/span&gt;造成的范围蔓延称为 “&lt;span class=&#34;red&#34;&gt;镀金&lt;/span&gt;”。&lt;/li&gt;
&lt;li&gt;来自团队&lt;span class=&#34;red&#34;&gt;外部原因&lt;/span&gt;造成的范围蔓延称为 “&lt;span class=&#34;red&#34;&gt;范围潜变&lt;/span&gt;”。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;dl&gt;
&lt;dt&gt;镀金&lt;/dt&gt;
&lt;dd&gt;项目人员为了 “&lt;span class=&#34;red&#34;&gt;讨好&lt;/span&gt;” 客户而做的&lt;span class=&#34;red&#34;&gt;不解决实际问题、没有应用价值&lt;/span&gt;的项目活动。&lt;/dd&gt;
&lt;dt&gt;范围潜变&lt;/dt&gt;
&lt;dd&gt;是指客户&lt;span class=&#34;red&#34;&gt;不断提出&lt;/span&gt;小的、&lt;span class=&#34;red&#34;&gt;不易察觉&lt;/span&gt;的范围改变，如果不加控制，累计起来导致项目严重偏离既定的范围基准，导致项目失控和失败&lt;/dd&gt;
&lt;/dl&gt;
&lt;blockquote&gt;
&lt;p&gt;如果已经出现了范围蔓延，一样需要走变更流程。&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h1 id=&#34;规划-规划范围管理&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#规划-规划范围管理&#34;&gt;#&lt;/a&gt;  &lt;code&gt;规划&lt;/code&gt;  规划范围管理&lt;/h1&gt;
&lt;ul&gt;
&lt;li&gt;创建范围管理计划，&lt;span class=&#34;red&#34;&gt;书面描述&lt;/span&gt;将&lt;span class=&#34;red&#34;&gt;如何定义、确认和控制项目范围&lt;/span&gt;的过程。&lt;/li&gt;
&lt;/ul&gt;
&lt;dl&gt;
&lt;dt&gt;本过程的作用&lt;/dt&gt;
&lt;dd&gt;在整个项目中对如何管理范围提供&lt;span class=&#34;red&#34;&gt;指南和方向&lt;/span&gt;。&lt;/dd&gt;
&lt;/dl&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;输入 &lt;code&gt;Input&lt;/code&gt;&lt;/th&gt;
&lt;th&gt;工具与技术 &lt;code&gt;Tool &amp;amp; Technology&lt;/code&gt;&lt;/th&gt;
&lt;th&gt;输出 &lt;code&gt;Output&lt;/code&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;项目管理计划&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;项目章程&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;事业环境因素&lt;/li&gt;
&lt;li&gt;组织过程资产&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;专家判断&lt;/li&gt;
&lt;li&gt;会议&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;范围管理计划&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;需求管理计划&lt;/span&gt;&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;输入&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输入&#34;&gt;#&lt;/a&gt; 输入&lt;/h2&gt;
&lt;h3 id=&#34;1️⃣-项目管理计划&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1️⃣-项目管理计划&#34;&gt;#&lt;/a&gt; 1️⃣ 项目管理计划&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;规划范围管理需要参照项目管理计划中&lt;span class=&#34;red&#34;&gt;已批准的子计划&lt;/span&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;2️⃣-项目章程&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2️⃣-项目章程&#34;&gt;#&lt;/a&gt; 2️⃣ 项目章程&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;依据项目章程中的项目背景信息来规划各个范围管理过程。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;输出&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输出&#34;&gt;#&lt;/a&gt; 输出&lt;/h2&gt;
&lt;h3 id=&#34;1️⃣-范围管理计划&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1️⃣-范围管理计划&#34;&gt;#&lt;/a&gt; 1️⃣ 范围管理计划&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;描述将&lt;span class=&#34;red&#34;&gt;如何&lt;/span&gt;定义、制定、监督、控制和确认项目范围。&lt;/li&gt;
&lt;/ul&gt;
&lt;dl&gt;
&lt;dt&gt;主要作用&lt;/dt&gt;
&lt;dd&gt;在整个项目中对如何管理范围提供&lt;span class=&#34;red&#34;&gt;指南和方向&lt;/span&gt;。&lt;/dd&gt;
&lt;/dl&gt;
&lt;blockquote&gt;
&lt;p&gt;注意点：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;&lt;ins&gt;范围管理计划无范围&lt;/ins&gt;&lt;br /&gt;
都是描述如何去管理范围，没有描述有哪些范围&lt;/li&gt;
&lt;li&gt;范围管理计划，&lt;ins&gt;有助于降低&lt;/ins&gt;项目&lt;ins&gt;范围蔓延&lt;/ins&gt;的风险&lt;br /&gt;
 &lt;code&gt;PMIS&lt;/code&gt;  里的子系统之一 —— 工作授权系统，有助于预防 “镀金”&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;dl&gt;
&lt;dt&gt;包含的内容：&lt;/dt&gt;
&lt;dd&gt;
&lt;ul&gt;
&lt;li&gt;如何制订项目范围说明书；&lt;/li&gt;
&lt;li&gt;如何根据范围说明书创建 WBS；&lt;/li&gt;
&lt;li&gt;如何维护和批准 WBS；&lt;/li&gt;
&lt;li&gt;如何确认和正式验收已完成的项目可交付成果；&lt;/li&gt;
&lt;li&gt;如何处理项目范围书的变更，该工作与实施整体变更控制过程直接相联；&lt;/li&gt;
&lt;/ul&gt;
&lt;/dd&gt;
&lt;/dl&gt;
&lt;blockquote&gt;
&lt;p&gt;所有 XX 管理计划中都有的通用内容，如：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;XX 管理会用到哪些工具和方法论；&lt;/li&gt;
&lt;li&gt;XX 管理用什么格式、多少频率进行汇报&lt;/li&gt;
&lt;li&gt;XX 管理中定了哪些岗位职责&lt;/li&gt;
&lt;li&gt;XX 管理预算花多少钱做，花多少时间做&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;2️⃣-需求管理计划&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2️⃣-需求管理计划&#34;&gt;#&lt;/a&gt; 2️⃣ 需求管理计划&lt;/h3&gt;
&lt;dl&gt;
&lt;dt&gt;需求管理&lt;/dt&gt;
&lt;dd&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;贯穿于整个过程&lt;/span&gt;，最基本的任务就是&lt;span class=&#34;red&#34;&gt;明确需求&lt;/span&gt;，并使项目团队和用户&lt;span class=&#34;red&#34;&gt;达成共识&lt;/span&gt;，即&lt;span class=&#34;red&#34;&gt;建立需求基线&lt;/span&gt;。&lt;/li&gt;
&lt;li&gt;还要建立&lt;span class=&#34;red&#34;&gt;需求跟踪能力联系链&lt;/span&gt;，确保所有用户需求都被正确地应用，并且在需求发生变更时，能够完全地&lt;span class=&#34;red&#34;&gt;控制其影响范围&lt;/span&gt;，始终&lt;span class=&#34;red&#34;&gt;保持产品与需求的一致性&lt;/span&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;/dd&gt;
&lt;dt&gt;需求管理计划&lt;/dt&gt;
&lt;dd&gt;描述在整个项目生命周期内，&lt;span class=&#34;red&#34;&gt;如何&lt;/span&gt;分析、记录和管理需求&lt;/dd&gt;
&lt;/dl&gt;
&lt;pre&gt;&lt;code&gt;&amp;gt; 需求管理计划无需求 
&lt;/code&gt;&lt;/pre&gt;
&lt;dl&gt;
&lt;dt&gt;包含的内容&lt;/dt&gt;
&lt;dd&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;如何&lt;/span&gt;规划、跟踪、报告各种需求活动；&lt;/li&gt;
&lt;li&gt;用什么标准对需求进行优先级&lt;span class=&#34;red&#34;&gt;排序&lt;/span&gt;；&lt;/li&gt;
&lt;li&gt;需求管理需要使用的&lt;span class=&#34;red&#34;&gt;资源&lt;/span&gt;；&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;培训计划&lt;/span&gt;；&lt;/li&gt;
&lt;li&gt;项目干系人&lt;span class=&#34;red&#34;&gt;参与&lt;/span&gt;需求管理的&lt;span class=&#34;red&#34;&gt;策略&lt;/span&gt;。&lt;/li&gt;
&lt;li&gt;判断项目范围与需求不一致的&lt;span class=&#34;red&#34;&gt;准则和纠正过程&lt;/span&gt;；&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;需求跟踪结构&lt;/span&gt;；&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;配置管理活动&lt;/span&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;/dd&gt;
&lt;/dl&gt;
&lt;h1 id=&#34;规划-收集需求&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#规划-收集需求&#34;&gt;#&lt;/a&gt;  &lt;code&gt;规划&lt;/code&gt;  收集需求&lt;/h1&gt;
&lt;dl&gt;
&lt;dt&gt;收集需求 &lt;code&gt;Collect Requirement&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;为实现项目目标而&lt;span class=&#34;red&#34;&gt;确定、记录&lt;/span&gt;并&lt;span class=&#34;red&#34;&gt;管理&lt;/span&gt;干系人的需要和需求的过程。&lt;/dd&gt;
&lt;dt&gt;本过程的作用&lt;/dt&gt;
&lt;dd&gt;为定义和管理项目范围（包括产品范围）奠定基础。&lt;/dd&gt;
&lt;/dl&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;输入 &lt;code&gt;Input&lt;/code&gt;&lt;/th&gt;
&lt;th&gt;工具与技术 &lt;code&gt;Tool &amp;amp; Technology&lt;/code&gt;&lt;/th&gt;
&lt;th&gt;输出 &lt;code&gt;Output&lt;/code&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;范围管理计划&lt;/li&gt;
&lt;li&gt;需求管理计划&lt;/li&gt;
&lt;li&gt;项目章程&lt;/li&gt;
&lt;li&gt;干系人管理计划&lt;/li&gt;
&lt;li&gt;干系人登记册&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;访谈&lt;/li&gt;
&lt;li&gt;焦点小组&lt;/li&gt;
&lt;li&gt;引导式研讨会&lt;/li&gt;
&lt;li&gt;群体创新技术&lt;/li&gt;
&lt;li&gt;群体决策技术&lt;/li&gt;
&lt;li&gt;问卷调查&lt;/li&gt;
&lt;li&gt;观察&lt;/li&gt;
&lt;li&gt;原型法&lt;/li&gt;
&lt;li&gt;标杆对照&lt;/li&gt;
&lt;li&gt;系统交互图&lt;/li&gt;
&lt;li&gt;文件分析&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;需求文件&lt;/li&gt;
&lt;li&gt;需求跟踪矩阵&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;输入-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输入-2&#34;&gt;#&lt;/a&gt; 输入&lt;/h2&gt;
&lt;h3 id=&#34;1️⃣-需求管理计划&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1️⃣-需求管理计划&#34;&gt;#&lt;/a&gt; 1️⃣ 需求管理计划&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;其中有描述 “整个收集需求过程的工作流程” 的规定&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;2️⃣-项目章程-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2️⃣-项目章程-2&#34;&gt;#&lt;/a&gt; 2️⃣ 项目章程&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;其中有 “产品、服务或成果的高层级描述”&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;3️⃣-干系人登记册&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3️⃣-干系人登记册&#34;&gt;#&lt;/a&gt; 3️⃣ 干系人登记册&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;其中有 “干系人对项目的主要需求和期望” 及 “哪些干系人能提供需求方面的信息” 等内容&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;工具与技术&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#工具与技术&#34;&gt;#&lt;/a&gt; 工具与技术&lt;/h2&gt;
&lt;h3 id=&#34;1️⃣-访谈&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1️⃣-访谈&#34;&gt;#&lt;/a&gt; 1️⃣ 访谈&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;通过与干系人&lt;span class=&#34;red&#34;&gt;直接交谈&lt;/span&gt;来获取信息。&lt;/li&gt;
&lt;li&gt;典型做法是向被访者提出&lt;span class=&#34;red&#34;&gt;预设&lt;/span&gt;和&lt;span class=&#34;red&#34;&gt;即兴&lt;/span&gt;的问题，并记录他们的回答。&lt;/li&gt;
&lt;/ul&gt;
&lt;dl&gt;
&lt;dt&gt;访谈分类&lt;/dt&gt;
&lt;dd&gt;
&lt;ul&gt;
&lt;li&gt;结构化：事先准备好一系列问题，有针对地进行；&lt;/li&gt;
&lt;li&gt;非结构化：只列出一个粗略的想法，根据访谈具体情况发挥。&lt;/li&gt;
&lt;/ul&gt;
&lt;/dd&gt;
&lt;/dl&gt;
&lt;blockquote&gt;
&lt;p&gt;关键词&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;直接交谈&lt;/li&gt;
&lt;li&gt;预设和即兴问题&lt;/li&gt;
&lt;li&gt;深入了解&lt;/li&gt;
&lt;li&gt;一对一、一对多&lt;/li&gt;
&lt;li&gt;获取&lt;span class=&#34;red&#34;&gt;机密和敏感&lt;/span&gt;的信息&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;p&gt;&lt;img data-src=&#34;https://i.loli.net/2021/07/25/HaVWlBuqhAnIxFg.png&#34; alt=&#34;&#34; title=&#34;麦肯锡方法&#34; /&gt;&lt;/p&gt;
&lt;h3 id=&#34;2️⃣-焦点小组&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2️⃣-焦点小组&#34;&gt;#&lt;/a&gt; 2️⃣ 焦点小组&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;由一位受过训练的&lt;span class=&#34;red&#34;&gt;主持人&lt;/span&gt;引导预先选定的干系人和&lt;span class=&#34;red&#34;&gt;主题专家&lt;/span&gt; &lt;code&gt;SME&lt;/code&gt;  进行&lt;span class=&#34;red&#34;&gt;互动式&lt;/span&gt;讨论。
&lt;ul&gt;
&lt;li&gt;焦点小组的参加者往往是&lt;span class=&#34;red&#34;&gt;同职能&lt;/span&gt;，&lt;span class=&#34;red&#34;&gt;同一领域&lt;/span&gt;、或&lt;span class=&#34;red&#34;&gt;有相似背景条件&lt;/span&gt;的人&lt;/li&gt;
&lt;li&gt;是 “一对多” 的&lt;span class=&#34;red&#34;&gt;群体访谈&lt;/span&gt;，最终是为了获取整个焦点小组&lt;span class=&#34;red&#34;&gt;更有价值&lt;/span&gt;的&lt;span class=&#34;red&#34;&gt;集体意见&lt;/span&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;blockquote&gt;
&lt;p&gt;关键词&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;同职能&lt;/li&gt;
&lt;li&gt;同一领域&lt;/li&gt;
&lt;li&gt;有相似背景&lt;/li&gt;
&lt;li&gt;主题专家 &lt;code&gt;SME&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;主持人&lt;/li&gt;
&lt;li&gt;互动式讨论&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;3️⃣-引导式研讨会&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3️⃣-引导式研讨会&#34;&gt;#&lt;/a&gt; 3️⃣ 引导式研讨会&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;把&lt;span class=&#34;red&#34;&gt;主要干系人&lt;/span&gt;召集在一起，通过&lt;span class=&#34;red&#34;&gt;集中讨论&lt;/span&gt;来定义产品需求（也需主持人）&lt;/li&gt;
&lt;li&gt;引导式研讨会能快速定义&lt;span class=&#34;red&#34;&gt;跨职能需求&lt;/span&gt;和&lt;span class=&#34;red&#34;&gt;协调干系人差异&lt;/span&gt;，着重于&lt;span class=&#34;red&#34;&gt;形成既定目标的一致意见&lt;/span&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;blockquote&gt;
&lt;p&gt;关键词&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;跨职能&lt;/li&gt;
&lt;li&gt;不同部门&lt;/li&gt;
&lt;li&gt;协调干系人差异&lt;/li&gt;
&lt;li&gt;联合应用开发 &lt;code&gt;JAD&lt;/code&gt;&lt;/li&gt;
&lt;li&gt;质量功能展开&lt;/li&gt;
&lt;li&gt;用户故事（敏捷）&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;blockquote&gt;
&lt;p&gt;常用的引导式研讨会：&lt;/p&gt;
&lt;dl&gt;
&lt;dt&gt;联合应用开发 &lt;code&gt;JAD&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;常用于&lt;strong&gt;软件开发行业&lt;/strong&gt;，强调由&lt;ins&gt;用户与项目开发团队一起&lt;/ins&gt;共同定义需求。&lt;/dd&gt;
&lt;dt&gt;质量功能展开 &lt;code&gt;QFD&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;常用于&lt;strong&gt;制造行业&lt;/strong&gt;。&lt;br /&gt;
三步骤：1、收集客户需要；2、分类和排序；3、设定目标；&lt;/dd&gt;
&lt;dt&gt;用户故事会&lt;/dt&gt;
&lt;dd&gt;常用于敏捷。&lt;br /&gt;
三部分构成：干系人角色，干系人想要什么，为什么想要它。&lt;/dd&gt;
&lt;/dl&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;4️⃣-群体创新技术&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4️⃣-群体创新技术&#34;&gt;#&lt;/a&gt; 4️⃣ 群体创新技术&lt;/h3&gt;
&lt;dl&gt;
&lt;dt&gt;群体创新技术  &lt;code&gt;Group Creativity Technique&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;通过一些群体活动来识别需求。&lt;/dd&gt;
&lt;/dl&gt;
&lt;blockquote&gt;
&lt;p&gt;重点在识别&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h4 id=&#34;头脑风暴&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#头脑风暴&#34;&gt;#&lt;/a&gt; 头脑风暴&lt;/h4&gt;
&lt;dl&gt;
&lt;dt&gt;头脑风暴（BrainStorming、BS、智力激励法、自由思考法、集思广益法）&lt;/dt&gt;
&lt;dd&gt;单纯地&lt;span class=&#34;red&#34;&gt;收集创意&lt;/span&gt;，不进行分析及投票或排序。&lt;/dd&gt;
&lt;dt&gt;直接头脑风暴法（头脑风暴法）&lt;/dt&gt;
&lt;dd&gt;&lt;span class=&#34;red&#34;&gt;尽可能激发&lt;/span&gt;创造性，&lt;span class=&#34;red&#34;&gt;产生尽可能多&lt;/span&gt;的设想；&lt;/dd&gt;
&lt;dt&gt;质疑头脑风暴法（反头脑风暴法）&lt;/dt&gt;
&lt;dd&gt;对提出的设想、方案&lt;span class=&#34;red&#34;&gt;逐一质疑&lt;/span&gt;，分析其现实可行性；&lt;/dd&gt;
&lt;/dl&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;参与人&lt;/strong&gt;：不同专业或岗位的 5~10 人；&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;时间&lt;/strong&gt;：1 小时左右；设主持人 (仅主持)、记录员 (完整记录)&lt;/p&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;&lt;strong&gt;头脑风暴的原则&lt;/strong&gt;：&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;庭外判决原则（不质疑、不分析、不批判、不反对）&lt;/li&gt;
&lt;li&gt;追求数量&lt;/li&gt;
&lt;li&gt;各抒己见、自由鸣放&lt;/li&gt;
&lt;li&gt;探索取长补短和改进办法；&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;blockquote&gt;
&lt;p&gt;关键词&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;畅所欲言&lt;/li&gt;
&lt;li&gt;单纯收集&lt;/li&gt;
&lt;li&gt;尽可能多&lt;/li&gt;
&lt;li&gt;尽可能激发&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h4 id=&#34;名义小组&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#名义小组&#34;&gt;#&lt;/a&gt; 名义小组&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;促进头脑风暴，通过&lt;span class=&#34;red&#34;&gt;投票&lt;/span&gt;排列最有用的创意，以便进一步头脑风暴或优先&lt;span class=&#34;red&#34;&gt;排序&lt;/span&gt;。&lt;/li&gt;
&lt;li&gt;名义小组技术是头脑风暴法的深化应用，是&lt;ins&gt;更加结构化&lt;/ins&gt;的头脑风暴法；&lt;/li&gt;
&lt;li&gt;名义小组技术可以使那些&lt;span class=&#34;red&#34;&gt;不善言辞的参与者&lt;/span&gt;也能&lt;span class=&#34;red&#34;&gt;充分发表&lt;/span&gt;自己的意见。&lt;/li&gt;
&lt;/ul&gt;
&lt;blockquote&gt;
&lt;p&gt;关键词&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;投票&lt;/li&gt;
&lt;li&gt;排序&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h4 id=&#34;德尔菲技术-delphi-technique&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#德尔菲技术-delphi-technique&#34;&gt;#&lt;/a&gt; 德尔菲技术  &lt;code&gt;Delphi Technique&lt;/code&gt;&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;
&lt;p&gt;一种组织&lt;span class=&#34;red&#34;&gt;专家&lt;/span&gt;就某一主题达成一致意见的一种信息收集技术。&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;专家回答问卷，并对&lt;span class=&#34;red&#34;&gt;每一轮&lt;/span&gt;给出反馈意见&lt;/li&gt;
&lt;li&gt;专家的答复只能交给主持人，以保持&lt;span class=&#34;red&#34;&gt;匿名&lt;/span&gt;状态。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;德尔菲技术的&lt;strong class=&#34;red&#34;&gt;主要缺点&lt;/strong&gt;是：过程比较复杂，花费时间较长。&lt;/p&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;blockquote&gt;
&lt;p&gt;关键词&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;专家&lt;/li&gt;
&lt;li&gt;匿名&lt;/li&gt;
&lt;li&gt;多轮&lt;/li&gt;
&lt;li&gt;趋同&lt;/li&gt;
&lt;li&gt;消除偏见&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h4 id=&#34;概念思维导图-mind-mapping&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#概念思维导图-mind-mapping&#34;&gt;#&lt;/a&gt; 概念 / 思维导图  &lt;code&gt;Mind Mapping&lt;/code&gt;&lt;/h4&gt;
&lt;dl&gt;
&lt;dt&gt;概念 / 思维导图（心智图、脑图）&lt;/dt&gt;
&lt;dd&gt;从头脑风暴中获得的创意&lt;span class=&#34;red&#34;&gt;整合&lt;/span&gt;成一张图，&lt;span class=&#34;red&#34;&gt;反映&lt;/span&gt;创意之间的&lt;span class=&#34;red&#34;&gt;共性与差异&lt;/span&gt;，&lt;span class=&#34;red&#34;&gt;激发新创意&lt;/span&gt;。&lt;/dd&gt;
&lt;/dl&gt;
&lt;blockquote&gt;
&lt;p&gt;关键词&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;整合&lt;/li&gt;
&lt;li&gt;反映共性与差异&lt;/li&gt;
&lt;li&gt;激发新创意&lt;/li&gt;
&lt;li&gt;图文并重&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h4 id=&#34;亲和图-affinity-diagram&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#亲和图-affinity-diagram&#34;&gt;#&lt;/a&gt; 亲和图  &lt;code&gt;Affinity Diagram&lt;/code&gt;&lt;/h4&gt;
&lt;dl&gt;
&lt;dt&gt;亲和图（KJ 法）&lt;/dt&gt;
&lt;dd&gt;从头脑风暴中获得的创意，根据&lt;span class=&#34;red&#34;&gt;相似性&lt;/span&gt;进行&lt;span class=&#34;red&#34;&gt;分组&lt;/span&gt;，以便进一步审查和分析。&lt;/dd&gt;
&lt;/dl&gt;
&lt;blockquote&gt;
&lt;p&gt;关键词&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;分组，归类&lt;/li&gt;
&lt;li&gt;有助于 WBS 制订&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h4 id=&#34;多标准决策分析&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#多标准决策分析&#34;&gt;#&lt;/a&gt; 多标准决策分析&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;如优先矩阵&lt;/li&gt;
&lt;li&gt;借助决策矩阵，用系统分析方法建立&lt;span class=&#34;red&#34;&gt;多种标准&lt;/span&gt;，可用于识别&lt;span class=&#34;red&#34;&gt;关键事项&lt;/span&gt;和合适的&lt;span class=&#34;red&#34;&gt;备选方案&lt;/span&gt;，并通过一系列决策对众多备选方案进行&lt;span class=&#34;red&#34;&gt;评估&lt;/span&gt;和&lt;span class=&#34;red&#34;&gt;排序&lt;/span&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;blockquote&gt;
&lt;p&gt;关键词&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;多种标准&lt;/li&gt;
&lt;li&gt;权重&lt;/li&gt;
&lt;li&gt;评估&lt;/li&gt;
&lt;li&gt;排序&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;5️⃣-群体决策技术&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#5️⃣-群体决策技术&#34;&gt;#&lt;/a&gt; 5️⃣ 群体决策技术&lt;/h3&gt;
&lt;dl&gt;
&lt;dt&gt;群体决策技术  &lt;code&gt;Group Decision-Making&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;为达成某种期望结果，对多个未来行动方案进行评估&lt;/dd&gt;
&lt;/dl&gt;
&lt;blockquote&gt;
&lt;p&gt;重点在&lt;ins&gt;决策&lt;/ins&gt;&lt;/p&gt;
&lt;/blockquote&gt;
&lt;ul&gt;
&lt;li&gt;分类：
&lt;ol&gt;
&lt;li&gt;一致同意  &lt;code&gt;Unanimity&lt;/code&gt; &lt;br /&gt;
 所有人都同意。&lt;/li&gt;
&lt;li&gt;大多数原则  &lt;code&gt;Majority&lt;/code&gt; &lt;br /&gt;
 群体中&lt;span class=&#34;red&#34;&gt;超过 50%&lt;/span&gt; 的人同意。&lt;br /&gt;
把参与决策的小组人数定为&lt;span class=&#34;red&#34;&gt;奇数&lt;/span&gt;，防止平局。&lt;/li&gt;
&lt;li&gt;相对多数原则  &lt;code&gt;Plurality&lt;/code&gt; &lt;br /&gt;
 群体中&lt;span class=&#34;red&#34;&gt;相对多数者&lt;/span&gt;同意，即便未能超过 50%。&lt;br /&gt;
通常在候选项超过两个时使用。&lt;/li&gt;
&lt;li&gt;独裁  &lt;code&gt;Dictatorship&lt;/code&gt; &lt;br /&gt;
 由某一个人做出决策。&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;6️⃣-问卷调查&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#6️⃣-问卷调查&#34;&gt;#&lt;/a&gt; 6️⃣ 问卷调查&lt;/h3&gt;
&lt;dl&gt;
&lt;dt&gt;问卷调查  &lt;code&gt;Questionnaire and Survey&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;设计一系列书面问题，向&lt;span class=&#34;red&#34;&gt;众多&lt;/span&gt;受访者&lt;span class=&#34;red&#34;&gt;快速&lt;/span&gt;收集信息。&lt;/dd&gt;
&lt;/dl&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;缺点&lt;/strong&gt;：
&lt;ul&gt;
&lt;li&gt;缺乏灵活性&lt;/li&gt;
&lt;li&gt;无法了解细节及更隐性的信息&lt;/li&gt;
&lt;li&gt;干系人不重视&lt;/li&gt;
&lt;li&gt;真实性差&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;blockquote&gt;
&lt;p&gt;关键词&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;受众多样化&lt;/li&gt;
&lt;li&gt;快速完成&lt;/li&gt;
&lt;li&gt;成本低&lt;/li&gt;
&lt;li&gt;地理位置分散&lt;/li&gt;
&lt;li&gt;适合开展统计分析&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;7️⃣-观察&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#7️⃣-观察&#34;&gt;#&lt;/a&gt; 7️⃣ 观察&lt;/h3&gt;
&lt;dl&gt;
&lt;dt&gt;观察  &lt;code&gt;Observation&lt;/code&gt; 、工作跟踪&lt;/dt&gt;
&lt;dd&gt;&lt;span class=&#34;red&#34;&gt;直接&lt;/span&gt;察看个人在各自的环境中如何执行工作和实施流程。&lt;/dd&gt;
&lt;/dl&gt;
&lt;blockquote&gt;
&lt;p&gt;关键词&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;直接察看&lt;/li&gt;
&lt;li&gt;难以或不愿清晰说明&lt;/li&gt;
&lt;li&gt;挖掘隐藏的需求&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;8️⃣-原型法&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#8️⃣-原型法&#34;&gt;#&lt;/a&gt; 8️⃣ 原型法&lt;/h3&gt;
&lt;dl&gt;
&lt;dt&gt;原型法  &lt;code&gt;Prototype&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;在实际制造产品之前，先造出&lt;span class=&#34;red&#34;&gt;实用模型&lt;/span&gt;，据此征求对需求的早期反馈。&lt;/dd&gt;
&lt;/dl&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;步骤&lt;/strong&gt;：
&lt;ol&gt;
&lt;li&gt;模型创建；&lt;/li&gt;
&lt;li&gt;用户体验；&lt;/li&gt;
&lt;li&gt;反馈收集；&lt;/li&gt;
&lt;li&gt;原型修改&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;blockquote&gt;
&lt;p&gt;关键词&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;减轻风险&lt;/li&gt;
&lt;li&gt;渐进明细&lt;/li&gt;
&lt;li&gt;敏捷&lt;/li&gt;
&lt;li&gt;故事板&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;9️⃣-标杆对照&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#9️⃣-标杆对照&#34;&gt;#&lt;/a&gt; 9️⃣ 标杆对照&lt;/h3&gt;
&lt;dl&gt;
&lt;dt&gt;标杆对照  &lt;code&gt;Benchmarking&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;将实际或计划做法与&lt;span class=&#34;red&#34;&gt;行业内&lt;/span&gt;或&lt;span class=&#34;red&#34;&gt;行业外&lt;/span&gt;的可比组织的做法进行比较，以便&lt;span class=&#34;red&#34;&gt;识别最佳实践&lt;/span&gt;，&lt;span class=&#34;red&#34;&gt;形成改进意见&lt;/span&gt;，并&lt;span class=&#34;red&#34;&gt;为绩效考核提供依据&lt;/span&gt;。&lt;/dd&gt;
&lt;/dl&gt;
&lt;blockquote&gt;
&lt;p&gt;关键词&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;可比组织、内部、外部、识别最佳实践、形成改进意见、为绩效考核提供依据&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;1️⃣0️⃣-系统交互图&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1️⃣0️⃣-系统交互图&#34;&gt;#&lt;/a&gt; 1️⃣0️⃣ 系统交互图&lt;/h3&gt;
&lt;dl&gt;
&lt;dt&gt;系统交互图  &lt;code&gt;Context Diagram&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;
&lt;ul&gt;
&lt;li&gt;范围模型的例子。&lt;/li&gt;
&lt;li&gt;是对产品范围的&lt;span class=&#34;red&#34;&gt;可视化&lt;/span&gt;描绘，显示业务系统以及与人和其他系统之间的交互方式&lt;/li&gt;
&lt;li&gt;如：DFD、用例图等&lt;/li&gt;
&lt;/ul&gt;
&lt;/dd&gt;
&lt;/dl&gt;
&lt;blockquote&gt;
&lt;p&gt;关键词&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;拓扑图&lt;/li&gt;
&lt;li&gt;可视化&lt;/li&gt;
&lt;/ul&gt;
&lt;/blockquote&gt;
&lt;h3 id=&#34;1️⃣1️⃣-文件分析&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1️⃣1️⃣-文件分析&#34;&gt;#&lt;/a&gt; 1️⃣1️⃣ 文件分析&lt;/h3&gt;
&lt;dl&gt;
&lt;dt&gt;文件分析  &lt;code&gt;Document Analysis&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;通过分析现有文档，识别与需求相 关的信息，来挖掘需求&lt;/dd&gt;
&lt;/dl&gt;
&lt;blockquote&gt;
&lt;p&gt;关键词：分析现有文档&lt;/p&gt;
&lt;/blockquote&gt;
&lt;h2 id=&#34;输出-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输出-2&#34;&gt;#&lt;/a&gt; 输出&lt;/h2&gt;
&lt;h3 id=&#34;1️⃣-需求文件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1️⃣-需求文件&#34;&gt;#&lt;/a&gt; 1️⃣ 需求文件&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;描述各种&lt;span class=&#34;red&#34;&gt;单一需求&lt;/span&gt;将&lt;span class=&#34;red&#34;&gt;如何满足&lt;/span&gt;与项目相关的&lt;span class=&#34;red&#34;&gt;业务需求&lt;/span&gt;。 &lt;code&gt;清单&lt;/code&gt;
&lt;ul&gt;
&lt;li&gt;&lt;code&gt;SRS&lt;/code&gt;  就是一种典型的需求文件&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;只有&lt;span class=&#34;red&#34;&gt;明确的&lt;/span&gt;（可测量和可测试的）、&lt;span class=&#34;red&#34;&gt;可跟踪的&lt;/span&gt;、&lt;span class=&#34;red&#34;&gt;完整的&lt;/span&gt;、&lt;span class=&#34;red&#34;&gt;相互协调的&lt;/span&gt;，且主要干系人&lt;span class=&#34;red&#34;&gt;认可的&lt;/span&gt;需求，才能作为基准。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;2️⃣-需求跟踪矩阵&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2️⃣-需求跟踪矩阵&#34;&gt;#&lt;/a&gt; 2️⃣ 需求跟踪矩阵&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;把&lt;span class=&#34;red&#34;&gt;产品（项目）需求&lt;/span&gt;从其来源&lt;span class=&#34;red&#34;&gt;连接到&lt;/span&gt;能满足需求的&lt;span class=&#34;red&#34;&gt;可交付成果&lt;/span&gt;的一种表格。
&lt;ul&gt;
&lt;li&gt;提供了在&lt;span class=&#34;red&#34;&gt;整个项目生命周期&lt;/span&gt;中&lt;span class=&#34;red&#34;&gt;跟踪需求&lt;/span&gt;的一种方法；&lt;/li&gt;
&lt;li&gt;把每个&lt;span class=&#34;red&#34;&gt;需求&lt;/span&gt;与&lt;span class=&#34;red&#34;&gt;业务目标&lt;/span&gt;或&lt;span class=&#34;red&#34;&gt;项目目标&lt;/span&gt;联系起来。&lt;/li&gt;
&lt;li&gt;收集需求时产生的&lt;span class=&#34;red&#34;&gt;需求文件和需求跟踪矩阵并不代表项目的真实&lt;/span&gt;&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img data-src=&#34;https://i.loli.net/2021/07/25/hBPjXp3yM5imLgG.jpg&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;箭头表示需求跟踪能力联系链，能跟踪需求使用的整个周期。
&lt;ul&gt;
&lt;li&gt;正向跟踪：原始需求 ➡️ 需求文件 ➡️ 产品&lt;/li&gt;
&lt;li&gt;反向跟踪（逆向跟踪）：产品 ➡️ 需求文件 ➡️ 原始需求；&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;规划-定义范围&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#规划-定义范围&#34;&gt;#&lt;/a&gt;  &lt;code&gt;规划&lt;/code&gt;  定义范围&lt;/h1&gt;
&lt;dl&gt;
&lt;dt&gt;定义范围 &lt;code&gt;Define Scope&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;制定项目和产品详细描述的过程。&lt;/dd&gt;
&lt;dt&gt;本过程的作用&lt;/dt&gt;
&lt;dd&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;明确&lt;/span&gt;所收集的需求哪些将&lt;span class=&#34;red&#34;&gt;包含在项目范围内&lt;/span&gt;，哪些将&lt;span class=&#34;red&#34;&gt;排除在项目范围外&lt;/span&gt;。&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;明确&lt;/span&gt;项目、服务或成果的&lt;span class=&#34;red&#34;&gt;边界&lt;/span&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;/dd&gt;
&lt;/dl&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;输入 &lt;code&gt;Input&lt;/code&gt;&lt;/th&gt;
&lt;th&gt;工具与技术 &lt;code&gt;Tool &amp;amp; Technology&lt;/code&gt;&lt;/th&gt;
&lt;th&gt;输出 &lt;code&gt;Output&lt;/code&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;范围管理计划&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;项目章程&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;需求文件&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;组织过程资产&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;专家判断&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;产品分析&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;备选方案生成&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;引导式研讨会&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;项目范围说明书&lt;/li&gt;
&lt;li&gt;项目文件更新&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;输入-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输入-3&#34;&gt;#&lt;/a&gt; 输入&lt;/h2&gt;
&lt;h3 id=&#34;1️⃣-项目章程&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1️⃣-项目章程&#34;&gt;#&lt;/a&gt; 1️⃣ 项目章程&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;项目章程中包含对项目和产品特征的高层级描述，它还包括项目审批要求。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;2️⃣-需求文件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2️⃣-需求文件&#34;&gt;#&lt;/a&gt; 2️⃣ 需求文件&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;使用需求文件来选择哪些需求将包含在项目中。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;工具与技术-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#工具与技术-2&#34;&gt;#&lt;/a&gt; 工具与技术&lt;/h2&gt;
&lt;h3 id=&#34;1️⃣-产品分析&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1️⃣-产品分析&#34;&gt;#&lt;/a&gt; 1️⃣ 产品分析&lt;/h3&gt;
&lt;dl&gt;
&lt;dt&gt;产品分析  &lt;code&gt;Product Analysis&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;把&lt;span class=&#34;red&#34;&gt;高层级的产品描述&lt;/span&gt;转变为&lt;span class=&#34;red&#34;&gt;有形的可交付成果&lt;/span&gt;。&lt;/dd&gt;
&lt;/dl&gt;
&lt;ul&gt;
&lt;li&gt;产品分析技术包括
&lt;ul&gt;
&lt;li&gt;产品分解&lt;/li&gt;
&lt;li&gt;系统分析&lt;/li&gt;
&lt;li&gt;需求分析&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;系统工程&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;价值工程&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;价值分析&lt;/span&gt;等。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;&lt;/th&gt;
&lt;th&gt;
&lt;p&gt;价值工程 &lt;code&gt;VE&lt;/code&gt; &lt;br /&gt;
Value Engineering&lt;/p&gt;
&lt;/th&gt;
&lt;th&gt;
&lt;p&gt;价值分析 &lt;code&gt;VA&lt;/code&gt; &lt;br /&gt;
Value Analysis&lt;/p&gt;
&lt;/th&gt;
&lt;/tr&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td rowspan=&#34;3&#34;&gt;不同点&lt;/td&gt;
&lt;td&gt;&lt;span class=&#34;red&#34;&gt;设计&lt;/span&gt;阶段使用&lt;/td&gt;
&lt;td&gt;&lt;span class=&#34;red&#34;&gt;生产&lt;/span&gt;阶段使用&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;分子（功能）可以改变&lt;/td&gt;
&lt;td&gt;分子（功能）&lt;span class=&#34;red&#34;&gt;不能变&lt;/span&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;分母（成本）可以改变&lt;/td&gt;
&lt;td&gt;分母（成本）&lt;span class=&#34;red&#34;&gt;可以降低&lt;/span&gt;来提高价值&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td rowspan=&#34;2&#34;&gt;相同点&lt;/td&gt;
&lt;td colspan=&#34;2&#34;&gt;都是对商品的&lt;span class=&#34;red&#34;&gt;价值、功能与成本&lt;/span&gt;进一步做思考与探索，以小组活动方式，集思广益朝各方向&lt;span class=&#34;red&#34;&gt;寻求最佳方案&lt;/span&gt;，再运用体系分工的方式达成价值提升或降低成本的目标，以&lt;span class=&#34;red&#34;&gt;达到价值最大化&lt;/span&gt;的方法。&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td colspan=&#34;2&#34;&gt;V（价值）＝F（功能）／C（成本）&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h3 id=&#34;2️⃣-备选方案生成&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2️⃣-备选方案生成&#34;&gt;#&lt;/a&gt; 2️⃣ 备选方案生成&lt;/h3&gt;
&lt;dl&gt;
&lt;dt&gt;备选方案生成  &lt;code&gt;Alternatives Generation&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;制定&lt;span class=&#34;red&#34;&gt;尽可能多&lt;/span&gt;的潜在可选方案的技术，用于识别执行项目工作的&lt;span class=&#34;red&#34;&gt;不同方法&lt;/span&gt;。&lt;/dd&gt;
&lt;/dl&gt;
&lt;ul&gt;
&lt;li&gt;可生成备选方案的技术有
&lt;ul&gt;
&lt;li&gt;头脑风暴&lt;/li&gt;
&lt;li&gt;横向思维&lt;/li&gt;
&lt;li&gt;备选方案分析等&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;dl&gt;
&lt;dt&gt;备选方案分析  &lt;code&gt;Alternatives Analysis&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;对已识别的可选方案进行评估，来决定选择哪种方案或方法来执行项目工作。&lt;/dd&gt;
&lt;dt&gt;横向思维  &lt;code&gt;Lateral Thinking&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;戴勃诺理论、发散 思维、水平思维，指思维的&lt;span class=&#34;red&#34;&gt;广阔度&lt;/span&gt;，要求人们能&lt;span class=&#34;red&#34;&gt;全面地&lt;/span&gt;观察问题，从事物多样的联系和关系中去认识事物，&lt;span class=&#34;red&#34;&gt;不一定有顺序&lt;/span&gt;，也&lt;span class=&#34;red&#34;&gt;不能预测&lt;/span&gt;。&lt;/dd&gt;
&lt;/dl&gt;
&lt;h2 id=&#34;输出-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输出-3&#34;&gt;#&lt;/a&gt; 输出&lt;/h2&gt;
&lt;h3 id=&#34;1️⃣-项目范围说明书&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1️⃣-项目范围说明书&#34;&gt;#&lt;/a&gt; 1️⃣ 项目范围说明书&lt;/h3&gt;
&lt;dl&gt;
&lt;dt&gt;项目范围说明书  &lt;code&gt;Project Scope Statement&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;是对项目范围、主要可交付成果、假设条件和制约因素的描述。记录了整个范围，包括&lt;span class=&#34;red&#34;&gt;项目和产品范围&lt;/span&gt;。&lt;/dd&gt;
&lt;/dl&gt;
&lt;ul&gt;
&lt;li&gt;项目范围说明书也代表项目干系人之间&lt;span class=&#34;red&#34;&gt;就项目范围所达成的共识&lt;/span&gt;。&lt;/li&gt;
&lt;li&gt;为了便于&lt;span class=&#34;red&#34;&gt;管理干系人的期望&lt;/span&gt;，项目范围说明书&lt;span class=&#34;red&#34;&gt;可明确指出哪些工作不属于本项目范围&lt;/span&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;包含的内容&lt;/th&gt;
&lt;th&gt;内容描述&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;产品范围描述&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;逐步细化在&lt;span class=&#34;red&#34;&gt;项目章程&lt;/span&gt;和&lt;span class=&#34;red&#34;&gt;需求文件&lt;/span&gt;中所述的产品、服务或成果的特征&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;验收标准&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;可交付成果通过验收前必须满足的一系列条件。&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;可交付成果&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;必须产出的任何独特并可核实的产品、成果或服务能力。也包括&lt;span class=&#34;red&#34;&gt;辅助成果&lt;/span&gt;，如项目管理报告和文件。&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;除外责任&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;明确说明哪些内容&lt;span class=&#34;red&#34;&gt;不属于项目范围&lt;/span&gt;，有助于管理干系人的期望。&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;制约因素&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;对项目或过程的执行有影响的限制性因素（如预算、里程碑、合同条款等）  &lt;code&gt;客观存在、确定的、应遵守&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;tr&gt;
&lt;td&gt;&lt;strong&gt;假设条件&lt;/strong&gt;&lt;/td&gt;
&lt;td&gt;不需验证即可视为正确、真实的因素。还应描述若这些因素不成立，可能造成的潜在影响  &lt;code&gt;有不确定性&lt;/code&gt;&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h1 id=&#34;规划-创建工作分解结构-wbs&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#规划-创建工作分解结构-wbs&#34;&gt;#&lt;/a&gt;  &lt;code&gt;规划&lt;/code&gt;  创建工作分解结构  &lt;code&gt;WBS&lt;/code&gt;&lt;/h1&gt;
&lt;dl&gt;
&lt;dt&gt;创建 WBS&lt;/dt&gt;
&lt;dd&gt;把项目可交付成果和项目工作分解成较小的、更易于管理的组件的过程。&lt;/dd&gt;
&lt;dt&gt;本过程的作用&lt;/dt&gt;
&lt;dd&gt;对所要交付的内容提供一个&lt;span class=&#34;red&#34;&gt;结构化&lt;/span&gt;的视图。&lt;/dd&gt;
&lt;/dl&gt;
&lt;ul&gt;
&lt;li&gt;WBS &lt;span class=&#34;red&#34;&gt;组织&lt;/span&gt;并&lt;span class=&#34;red&#34;&gt;定义&lt;/span&gt;了项目的总范围
&lt;ul&gt;
&lt;li&gt;项目范围说明书只定义范围，没有组织范围&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;WBS 中的 “工作” 并不是指工作本身，而是指工作所导致的&lt;span class=&#34;red&#34;&gt;产品或可交付成果&lt;/span&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;输入 &lt;code&gt;Input&lt;/code&gt;&lt;/th&gt;
&lt;th&gt;工具与技术 &lt;code&gt;Tool &amp;amp; Technology&lt;/code&gt;&lt;/th&gt;
&lt;th&gt;输出 &lt;code&gt;Output&lt;/code&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;范围管理计划&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;项目范围说明书&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;需求文件&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;事业环境因素&lt;/li&gt;
&lt;li&gt;组织过程资产&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;分解&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;专家判断&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;范围基准&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;项目文件更新&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;输入-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输入-4&#34;&gt;#&lt;/a&gt; 输入&lt;/h2&gt;
&lt;h3 id=&#34;1️⃣-范围管理计划-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1️⃣-范围管理计划-2&#34;&gt;#&lt;/a&gt; 1️⃣ 范围管理计划&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;定义了应该&lt;span class=&#34;red&#34;&gt;如何&lt;/span&gt;根据详细项目范围说明书&lt;span class=&#34;red&#34;&gt;创建 WBS&lt;/span&gt;，以及应该&lt;span class=&#34;red&#34;&gt;如何维护和批准 WBS&lt;/span&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;2️⃣-项目范围说明书&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2️⃣-项目范围说明书&#34;&gt;#&lt;/a&gt; 2️⃣ 项目范围说明书&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;描述了&lt;span class=&#34;red&#34;&gt;需要实施的&lt;/span&gt;工作及&lt;span class=&#34;red&#34;&gt;不包含在项目中的&lt;/span&gt;工作，同时也列举和描述了会影响项目执行的各种内外&lt;span class=&#34;red&#34;&gt;部制约或限制条件&lt;/span&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;3️⃣-需求文件&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3️⃣-需求文件&#34;&gt;#&lt;/a&gt; 3️⃣ 需求文件&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;对理解&lt;span class=&#34;red&#34;&gt;需要产出什么项目结果&lt;/span&gt;，&lt;span class=&#34;red&#34;&gt;需要做什么来交付项目&lt;/span&gt;及其最终产品，都非常重要。&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;工具与技术-3&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#工具与技术-3&#34;&gt;#&lt;/a&gt; 工具与技术&lt;/h2&gt;
&lt;h3 id=&#34;1️⃣-分解&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1️⃣-分解&#34;&gt;#&lt;/a&gt; 1️⃣ 分解&lt;/h3&gt;
&lt;dl&gt;
&lt;dt&gt;分解&lt;/dt&gt;
&lt;dd&gt;把项目范围和项目可交付成果&lt;span class=&#34;red&#34;&gt;逐步划分&lt;/span&gt;为更小、更便于管理的组成部分的技术。&lt;/dd&gt;
&lt;/dl&gt;
&lt;blockquote&gt;
&lt;p&gt;创建 WBS，就是要将整个项目工作分解为工作包&lt;/p&gt;
&lt;/blockquote&gt;
&lt;dl&gt;
&lt;dt&gt;工作包  &lt;code&gt;Work Package&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;
&lt;ul&gt;
&lt;li&gt;位于 WBS 每条分支&lt;span class=&#34;red&#34;&gt;最底层&lt;/span&gt;的&lt;span class=&#34;red&#34;&gt;可交付成果&lt;/span&gt;或项目&lt;span class=&#34;red&#34;&gt;工作组成部分&lt;/span&gt;，可对其&lt;span class=&#34;red&#34;&gt;成本&lt;/span&gt;和&lt;span class=&#34;red&#34;&gt;持续时间&lt;/span&gt;进行估算和管理。&lt;/li&gt;
&lt;li&gt;工作包大小应在&lt;span class=&#34;red&#34;&gt; 8~80 小时&lt;/span&gt;之间。（P-238）&lt;/li&gt;
&lt;/ul&gt;
&lt;/dd&gt;
&lt;/dl&gt;
&lt;h4 id=&#34;wbs分解的5步骤&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#wbs分解的5步骤&#34;&gt;#&lt;/a&gt; WBS 分解的 5 步骤&lt;/h4&gt;
&lt;p&gt;&lt;img data-src=&#34;https://i.loli.net/2021/07/26/qlLUMVrSwKfpNXg.png&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;ol&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;识别和分析&lt;/span&gt;可交付成果及相关工作
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;范围说明书&lt;/strong&gt;中规定的可交付成果&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;确定&lt;/span&gt; WBS 的&lt;span class=&#34;red&#34;&gt;结构和编排方法&lt;/span&gt;
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;范围管理计划&lt;/strong&gt;是此步的指南&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;自上而下&lt;/span&gt;逐层细化&lt;span class=&#34;red&#34;&gt;分解&lt;/span&gt;
&lt;ul&gt;
&lt;li&gt;使用&lt;strong&gt;分解&lt;/strong&gt;工具&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;为 WBS 组件制定和&lt;span class=&#34;red&#34;&gt;分配标识编码&lt;/span&gt;
&lt;ul&gt;
&lt;li&gt;编码后可以了解哪些工作包是同一层的&lt;/li&gt;
&lt;li&gt;可以了解不同颗粒度的可交付成果的层级关系&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;核实&lt;/span&gt;可交付成果分解的程度是否恰当
&lt;ul&gt;
&lt;li&gt;核实有没有分解错误&lt;/li&gt;
&lt;li&gt;核实完成后能不能完成原始需求&lt;/li&gt;
&lt;li&gt;所以需要&lt;strong&gt;需求文件&lt;/strong&gt;来核实&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h4 id=&#34;wbs分解的3个方式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#wbs分解的3个方式&#34;&gt;#&lt;/a&gt; WBS 分解的 3 个方式&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;把&lt;span class=&#34;red&#34;&gt;项目生命周期的各阶段&lt;/span&gt;放在第二层&lt;br /&gt;
&lt;img data-src=&#34;https://i.loli.net/2021/07/26/k79O8KWnh62mBuY.jpg&#34; alt=&#34;&#34; /&gt;&lt;/li&gt;
&lt;li&gt;把&lt;span class=&#34;red&#34;&gt;可交付成果&lt;/span&gt;放在第二层&lt;br /&gt;
&lt;img data-src=&#34;https://i.loli.net/2021/07/26/qlLUMVrSwKfpNXg.png&#34; alt=&#34;&#34; /&gt;&lt;/li&gt;
&lt;li&gt;整合可能由项目团队以外的组织来实施的各种子组件（如&lt;span class=&#34;red&#34;&gt;外包工作&lt;/span&gt;）。作为外包工作的一部分，卖方需编制相应的合同 WBS。&lt;/li&gt;
&lt;/ol&gt;
&lt;h4 id=&#34;wbs分解的6个原则&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#wbs分解的6个原则&#34;&gt;#&lt;/a&gt; WBS 分解的 6 个原则&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;
&lt;p&gt;100% 原则（包含原则）&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;仅包括所有可交付成果&lt;/li&gt;
&lt;li&gt;所有下一级的元素之和必须 100% 地代表上一级元素&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;独立责任原则&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;每个元素有且只有一个人负责&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;80 小时原则&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;工作包大小在 8~80 小时之间&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;4~6 层指导&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;不宜过细分解&lt;/li&gt;
&lt;li&gt;每一层建议 4~7 个元素&lt;/li&gt;
&lt;li&gt;超过 6 层仍不能分完，则考虑项目太大，建议分成子项目再分各自的 WBS&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;滚动分解原则&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;渐进明细&lt;/li&gt;
&lt;li&gt;并非一成不变&lt;/li&gt;
&lt;li&gt;暂时分解不了时，可以先放在一边，成为一个&lt;strong&gt;规划包&lt;/strong&gt;，待未来明确后再分&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;
&lt;p&gt;功能或技术原则&lt;/p&gt;
&lt;ul&gt;
&lt;li&gt;分解时需考虑将不同人员的工作分开&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h4 id=&#34;wbs分解的6个注意&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#wbs分解的6个注意&#34;&gt;#&lt;/a&gt; WBS 分解的 6 个注意&lt;/h4&gt;
&lt;ul&gt;
&lt;li&gt;WBS 必须是&lt;span class=&#34;red&#34;&gt;面向可交付成果&lt;/span&gt;的。&lt;/li&gt;
&lt;li&gt;WBS 应包括&lt;span class=&#34;red&#34;&gt;项目管理工作&lt;/span&gt;，也要包括&lt;span class=&#34;red&#34;&gt;分包&lt;/span&gt;出去的工作。&lt;/li&gt;
&lt;li&gt;WBS 的编制需要&lt;span class=&#34;red&#34;&gt;所有（主要）项目干系人的参与&lt;/span&gt;，需要&lt;span class=&#34;red&#34;&gt;项目团队成员的参与&lt;/span&gt;。&lt;/li&gt;
&lt;li&gt;不同的可交付成果&lt;span class=&#34;red&#34;&gt;可以分解到不同&lt;/span&gt;的层次
&lt;ul&gt;
&lt;li&gt;并不是分解得越细越好。&lt;/li&gt;
&lt;li&gt;过细的分解，资源使用效率低下、工作实施效率降低等等。&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;远期才完成的可交付成果或组件，当前可能无法分解（&lt;span class=&#34;red&#34;&gt;规划包&lt;/span&gt;），需要&lt;span class=&#34;red&#34;&gt;滚动式规划&lt;/span&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;h4 id=&#34;wbs的3种表现形式&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#wbs的3种表现形式&#34;&gt;#&lt;/a&gt; WBS 的 3 种表现形式&lt;/h4&gt;
&lt;ol&gt;
&lt;li&gt;树型结构（组织结构图式）
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;优点&lt;/strong&gt;：层次清晰、直观性和结构性强&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;缺点&lt;/strong&gt;：不容易修改，很难表示大的、复杂的项目全貌&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;表格形式（列表式）
&lt;ul&gt;
&lt;li&gt;&lt;strong&gt;优点&lt;/strong&gt;：能反映出项目所有的工作要素&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;缺点&lt;/strong&gt;：直观性较差&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;li&gt;鱼骨图
&lt;ul&gt;
&lt;li&gt;不常用&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ol&gt;
&lt;h4 id=&#34;控制账户&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#控制账户&#34;&gt;#&lt;/a&gt; 控制账户&lt;/h4&gt;
&lt;dl&gt;
&lt;dt&gt;控制账户  &lt;code&gt;Control Account&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;是一个管理控制点（可以&lt;span class=&#34;red&#34;&gt;与组织的财务程序链接&lt;/span&gt;），在该控制点上，把范围、预算、实际成本和进度加以整合，并&lt;span class=&#34;red&#34;&gt;与挣值相比较，以测量绩效&lt;/span&gt;。&lt;/dd&gt;
&lt;/dl&gt;
&lt;ul&gt;
&lt;li&gt;每个控制账户&lt;span class=&#34;red&#34;&gt;可能包括一个或多个&lt;/span&gt;工作包（或规划包），但是&lt;span class=&#34;red&#34;&gt;一个工作包只能属于一个控制账户&lt;/span&gt;。&lt;/li&gt;
&lt;li&gt;控制账户设在&lt;span class=&#34;red&#34;&gt;较高层次&lt;/span&gt;上还是&lt;span class=&#34;red&#34;&gt;较低层次&lt;/span&gt;上，就表明项目管理团队想要对项目实施 “&lt;span class=&#34;red&#34;&gt;粗管&lt;/span&gt;” 还是 “&lt;span class=&#34;red&#34;&gt;细管&lt;/span&gt;”。&lt;/li&gt;
&lt;/ul&gt;
&lt;p&gt;&lt;img data-src=&#34;https://i.loli.net/2021/07/26/rMzLhEFyC8c4Pal.jpg&#34; alt=&#34;&#34; /&gt;&lt;/p&gt;
&lt;h2 id=&#34;输出-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输出-4&#34;&gt;#&lt;/a&gt; 输出&lt;/h2&gt;
&lt;h3 id=&#34;1️⃣-范围基准&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1️⃣-范围基准&#34;&gt;#&lt;/a&gt; 1️⃣ 范围基准&lt;/h3&gt;
&lt;dl&gt;
&lt;dt&gt;范围基准&lt;/dt&gt;
&lt;dd&gt;经过&lt;span class=&#34;red&#34;&gt;批准&lt;/span&gt;的&lt;span class=&#34;red&#34;&gt;项目范围说明书、WBS、WBS 词典&lt;/span&gt;，只有通过&lt;span class=&#34;red&#34;&gt;正式的变更控制程序&lt;/span&gt;才能进行变更，它被用作比较的基础。&lt;/dd&gt;
&lt;dt&gt;项目范围说明书&lt;/dt&gt;
&lt;dd&gt;
&lt;ul&gt;
&lt;li&gt;是对项目范围、主要可交付成果、假设条件和制约因素的描述。记录了整个范围，&lt;span class=&#34;red&#34;&gt;包括项目和产品范围&lt;/span&gt;。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;包括&lt;/strong&gt;
&lt;ul&gt;
&lt;li&gt;产品范围描述&lt;/li&gt;
&lt;li&gt;验收标准&lt;/li&gt;
&lt;li&gt;可交付成果&lt;/li&gt;
&lt;li&gt;项目的除外责任&lt;/li&gt;
&lt;li&gt;制约因素&lt;/li&gt;
&lt;li&gt;假设条件&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/dd&gt;
&lt;dt&gt;WBS&lt;/dt&gt;
&lt;dd&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;全部&lt;/span&gt;工作范围的&lt;span class=&#34;red&#34;&gt;层级&lt;/span&gt;分解。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;有助于防止范围蔓延&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;包括&lt;/strong&gt;
&lt;ul&gt;
&lt;li&gt;工作包&lt;/li&gt;
&lt;li&gt;规划包&lt;/li&gt;
&lt;li&gt;控制帐户&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/dd&gt;
&lt;dt&gt;WBS 词典&lt;/dt&gt;
&lt;dd&gt;
&lt;ul&gt;
&lt;li&gt;针对&lt;span class=&#34;red&#34;&gt;每个&lt;/span&gt; WBS 组件，&lt;span class=&#34;red&#34;&gt;详细&lt;/span&gt;描述可交付成果、活动和进度信息的文件。&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;有助于评价变更的影响&lt;/strong&gt;&lt;/li&gt;
&lt;li&gt;&lt;strong&gt;包括&lt;/strong&gt;
&lt;ul&gt;
&lt;li&gt;账户编码标志号；&lt;/li&gt;
&lt;li&gt;工作描述；&lt;/li&gt;
&lt;li&gt;负责的组织；&lt;/li&gt;
&lt;li&gt;进度里程碑清单；&lt;/li&gt;
&lt;li&gt;相关的进度活动；&lt;/li&gt;
&lt;li&gt;所需的资源；&lt;/li&gt;
&lt;li&gt;成本估算；&lt;/li&gt;
&lt;li&gt;质量要求；&lt;/li&gt;
&lt;li&gt;验收标准；&lt;/li&gt;
&lt;li&gt;技术参考文献；&lt;/li&gt;
&lt;li&gt;协议信息；&lt;/li&gt;
&lt;/ul&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;/dd&gt;
&lt;/dl&gt;
&lt;h1 id=&#34;监控-控制范围&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#监控-控制范围&#34;&gt;#&lt;/a&gt;  &lt;code&gt;监控&lt;/code&gt;  控制范围&lt;/h1&gt;
&lt;dl&gt;
&lt;dt&gt;控制范围  &lt;code&gt;Control Scope&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;监督项目和产品的范围状态，管理范围基准变更的过程。&lt;/dd&gt;
&lt;dt&gt;本过程的作用&lt;/dt&gt;
&lt;dd&gt;
&lt;ul&gt;
&lt;li&gt;在整个项目期间保持对范围基准的维护。&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;确保所有&lt;/span&gt;变更请求、纠正措施、预防措施&lt;span class=&#34;red&#34;&gt;都通过&lt;/span&gt;实施整体变更控制过程进行处理。&lt;/li&gt;
&lt;/ul&gt;
&lt;/dd&gt;
&lt;/dl&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;输入 &lt;code&gt;Input&lt;/code&gt;&lt;/th&gt;
&lt;th&gt;工具与技术 &lt;code&gt;Tool &amp;amp; Technology&lt;/code&gt;&lt;/th&gt;
&lt;th&gt;输出 &lt;code&gt;Output&lt;/code&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;项目管理计划&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;需求文件&lt;/li&gt;
&lt;li&gt;需求跟踪矩阵&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;工作绩效数据&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;组织过程资产&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;偏差分析&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;工作绩效信息&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;变更请求&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;项目管理计划更新&lt;/li&gt;
&lt;li&gt;项目文件更新&lt;/li&gt;
&lt;li&gt;组织过程资产更新&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;工具与技术-4&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#工具与技术-4&#34;&gt;#&lt;/a&gt; 工具与技术&lt;/h2&gt;
&lt;h3 id=&#34;1️⃣-偏差分析&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1️⃣-偏差分析&#34;&gt;#&lt;/a&gt; 1️⃣ 偏差分析&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;一种&lt;span class=&#34;red&#34;&gt;确定实际绩效&lt;/span&gt;与&lt;span class=&#34;red&#34;&gt;基准&lt;/span&gt;的&lt;span class=&#34;red&#34;&gt;差异程度及原因&lt;/span&gt;的技术。&lt;/li&gt;
&lt;li&gt;可利用项目绩效测量结果评估偏离范围基准的程度。&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;监控-确认范围&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#监控-确认范围&#34;&gt;#&lt;/a&gt;  &lt;code&gt;监控&lt;/code&gt;  确认范围&lt;/h1&gt;
&lt;dl&gt;
&lt;dt&gt;确认范围  &lt;code&gt;Validate Scope&lt;/code&gt;&lt;/dt&gt;
&lt;dd&gt;老版叫核实范围，“&lt;span class=&#34;red&#34;&gt;客户&lt;/span&gt;” 或 “&lt;span class=&#34;red&#34;&gt;发起人&lt;/span&gt;”&lt;span class=&#34;red&#34;&gt; 正式验收&lt;/span&gt;已完成的项目可交付成果的过程。&lt;/dd&gt;
&lt;dt&gt;本过程的作用&lt;/dt&gt;
&lt;dd&gt;
&lt;ul&gt;
&lt;li&gt;使验收过程具有客观性；&lt;/li&gt;
&lt;li&gt;通过验收每个可交付成果，提高最终产品、服务或成果验收的可能性。&lt;/li&gt;
&lt;/ul&gt;
&lt;/dd&gt;
&lt;/dl&gt;
&lt;table&gt;
&lt;thead&gt;
&lt;tr&gt;
&lt;th&gt;输入 &lt;code&gt;Input&lt;/code&gt;&lt;/th&gt;
&lt;th&gt;工具与技术 &lt;code&gt;Tool &amp;amp; Technology&lt;/code&gt;&lt;/th&gt;
&lt;th&gt;输出 &lt;code&gt;Output&lt;/code&gt;&lt;/th&gt;
&lt;/tr&gt;
&lt;/thead&gt;
&lt;tbody&gt;
&lt;tr&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;项目管理计划&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;需求文件&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;需求跟踪矩阵&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;核实的可交付成果&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;工作绩效数据&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;检查&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;群体决策技术&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;td&gt;
&lt;ol&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;验收的可交付成果&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;变更请求&lt;/span&gt;&lt;/li&gt;
&lt;li&gt;工作绩效信息&lt;/li&gt;
&lt;li&gt;项目文件更新&lt;/li&gt;
&lt;/ol&gt;
&lt;/td&gt;
&lt;/tr&gt;
&lt;/tbody&gt;
&lt;/table&gt;
&lt;h2 id=&#34;输入-5&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#输入-5&#34;&gt;#&lt;/a&gt; 输入&lt;/h2&gt;
&lt;h3 id=&#34;1️⃣-项目管理计划-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1️⃣-项目管理计划-2&#34;&gt;#&lt;/a&gt; 1️⃣ 项目管理计划&lt;/h3&gt;
&lt;dl&gt;
&lt;dt&gt;范围管理计划&lt;/dt&gt;
&lt;dd&gt;定义了&lt;span class=&#34;red&#34;&gt;如何正式验收&lt;/span&gt;已完成的可交付成果；&lt;/dd&gt;
&lt;dt&gt;需求管理计划&lt;/dt&gt;
&lt;dd&gt;描述了&lt;span class=&#34;red&#34;&gt;如何确认项目需求&lt;/span&gt;；&lt;/dd&gt;
&lt;dt&gt;范围基准&lt;/dt&gt;
&lt;dd&gt;&lt;span class=&#34;red&#34;&gt;用范围基准与实际结果比较&lt;/span&gt;，以决定是否有必要进行变更、采取纠正措施或预防；&lt;/dd&gt;
&lt;/dl&gt;
&lt;h3 id=&#34;2️⃣-需求文件-2&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2️⃣-需求文件-2&#34;&gt;#&lt;/a&gt; 2️⃣ 需求文件&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;将需求与实际结果比较&lt;/span&gt;，以决定是否有必要进行变更、采取纠正措施或预防措施&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;3️⃣-需求跟踪矩阵&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3️⃣-需求跟踪矩阵&#34;&gt;#&lt;/a&gt; 3️⃣ 需求跟踪矩阵&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;含有&lt;span class=&#34;red&#34;&gt;与需求相关的信息&lt;/span&gt;，包括如何确认需求&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;4️⃣-核实的可交付成果&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#4️⃣-核实的可交付成果&#34;&gt;#&lt;/a&gt; 4️⃣ 核实的可交付成果&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;&lt;span class=&#34;red&#34;&gt;已完成&lt;/span&gt;，并由&lt;span class=&#34;red&#34;&gt;控制质量&lt;/span&gt;过程&lt;span class=&#34;red&#34;&gt;核实为正确&lt;/span&gt;的可交付成果；&lt;/li&gt;
&lt;/ul&gt;
&lt;h2 id=&#34;工具与技术-5&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#工具与技术-5&#34;&gt;#&lt;/a&gt; 工具与技术&lt;/h2&gt;
&lt;h3 id=&#34;1️⃣-检查&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#1️⃣-检查&#34;&gt;#&lt;/a&gt; 1️⃣ 检查&lt;/h3&gt;
&lt;dl&gt;
&lt;dt&gt;检查（审查、评审、走查、巡检、测试）&lt;/dt&gt;
&lt;dd&gt;是指开展测量、审查与确认等活动，来判断&lt;span class=&#34;red&#34;&gt;工作&lt;/span&gt;和&lt;span class=&#34;red&#34;&gt;可交付成果&lt;/span&gt;是否&lt;span class=&#34;red&#34;&gt;符合需求和产品验收标准&lt;/span&gt;&lt;/dd&gt;
&lt;/dl&gt;
&lt;ul&gt;
&lt;li&gt;验收测试就是一种典型的确认范围的技术。&lt;/li&gt;
&lt;li&gt;检查和审计的区别：&lt;strong&gt;检查的是结果&lt;/strong&gt;，&lt;strong&gt;审计的是过程&lt;/strong&gt;。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;2️⃣-验收的可交付成果&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#2️⃣-验收的可交付成果&#34;&gt;#&lt;/a&gt; 2️⃣ 验收的可交付成果&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;符合验收标准的可交付成果&lt;span class=&#34;red&#34;&gt;应该由客户或发起人正式签字批准&lt;/span&gt;。&lt;/li&gt;
&lt;li&gt;应该从客户或发起人那里获得&lt;span class=&#34;red&#34;&gt;正式文件&lt;/span&gt;，证明干系人对项目可交付成果的正式验收。&lt;/li&gt;
&lt;/ul&gt;
&lt;h3 id=&#34;3️⃣-变更请求&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#3️⃣-变更请求&#34;&gt;#&lt;/a&gt; 3️⃣ 变更请求&lt;/h3&gt;
&lt;ul&gt;
&lt;li&gt;如果未通过验收，处理步骤：
&lt;ol&gt;
&lt;li&gt;记录原因；&lt;/li&gt;
&lt;li&gt;提交变更请求；&lt;/li&gt;
&lt;li&gt;进行缺陷补救。&lt;/li&gt;
&lt;/ol&gt;
&lt;/li&gt;
&lt;/ul&gt;
&lt;h1 id=&#34;总结&#34;&gt;&lt;a class=&#34;anchor&#34; href=&#34;#总结&#34;&gt;#&lt;/a&gt; 总结&lt;/h1&gt;
&lt;table&gt;
&lt;thead&gt;
